        return isinstance(output, list) and len(output) == 0
    if not isinstance(output, list):
        return False
    seen = set()
    total = 0
    for v in output:
        if not isinstance(v, int) or isinstance(v, bool):
            return False
        if v <= 0 or v % 2 != 0:
            return False
        if v in seen:
            return False
        seen.add(v)
        total += v
