import math
class Solution:
    def maximumEvenSplit(self, finalSum: int):
        if finalSum % 2 != 0:
            return []
        k = int((-1 + math.isqrt(1 + 4 * finalSum)) // 2)
        while k * (k + 1) > finalSum:
            k -= 1
        while (k + 1) * (k + 2) <= finalSum:
            k += 1
        if k == 0:
            return []
        remainder = finalSum - k * (k + 1)
        res = [2 * i for i in range(1, k + 1)]
        res[-1] += remainder
        return res

