class Solution:
    def maximumEvenSplit(self, finalSum: int):
        if finalSum % 2 != 0:
            return []
        result = []
        cur = 2
        remaining = finalSum
        while remaining >= cur:
            result.append(cur)
            remaining -= cur
            cur += 2
        if result:
            result[-1] += remaining
        return result

