    if (finalSum % 2 !== 0) return [];
    const result = [];
    let cur = 2;
    let remaining = finalSum;
    while (remaining >= cur) {
        result.push(cur);
        remaining -= cur;
        cur += 2;
    }
    if (result.length > 0) {
        result[result.length - 1] += remaining;
    }
    return result;
